import {
  validateShipmentRequest,
  ShipmentRequest,
} from "./validateShipmentRequest";

describe("validateShipmentRequest", () => {
  // ── AC1: valid request returns { valid: true, errors: [] } ──────────────────

  it("AC1: returns valid=true and empty errors for a fully valid express request", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: 10,
      shipment_type: "express",
      saturday_delivery: true,
    };
    expect(validateShipmentRequest(input)).toEqual({ valid: true, errors: [] });
  });

  it("AC1: returns valid=true and empty errors for a fully valid standard request", () => {
    const input: ShipmentRequest = {
      recipient_name: "John Smith",
      weight_kg: 5,
      shipment_type: "standard",
    };
    expect(validateShipmentRequest(input)).toEqual({ valid: true, errors: [] });
  });

  // ── AC2: recipient_name missing or empty ────────────────────────────────────

  it("AC2: errors when recipient_name is missing", () => {
    const input: ShipmentRequest = {
      weight_kg: 10,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "recipient_name",
      code: "REQUIRED",
    });
  });

  it("AC2: errors when recipient_name is an empty string", () => {
    const input: ShipmentRequest = {
      recipient_name: "",
      weight_kg: 10,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "recipient_name",
      code: "REQUIRED",
    });
  });

  it("AC2: errors when recipient_name is whitespace only", () => {
    const input: ShipmentRequest = {
      recipient_name: "   ",
      weight_kg: 10,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "recipient_name",
      code: "REQUIRED",
    });
  });

  // ── AC3: weight_kg is 0 or negative ────────────────────────────────────────

  it("AC3: errors when weight_kg is 0", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: 0,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "weight_kg",
      code: "MUST_BE_POSITIVE",
    });
  });

  it("AC3: errors when weight_kg is negative", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: -5,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "weight_kg",
      code: "MUST_BE_POSITIVE",
    });
  });

  // ── AC4: weight_kg exceeds 1000 ─────────────────────────────────────────────

  it("AC4: errors when weight_kg is greater than 1000", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: 1001,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "weight_kg",
      code: "EXCEEDS_MAX",
    });
  });

  it("AC4: does NOT error when weight_kg is exactly 1000 (boundary)", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: 1000,
      shipment_type: "standard",
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).not.toContainEqual({
      field: "weight_kg",
      code: "EXCEEDS_MAX",
    });
  });

  // ── AC5: express requires saturday_delivery ─────────────────────────────────

  it("AC5: errors when shipment_type is express and saturday_delivery is not provided", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: 10,
      shipment_type: "express",
      // saturday_delivery omitted
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).toContainEqual({
      field: "saturday_delivery",
      code: "REQUIRED_FOR_EXPRESS",
    });
  });

  it("AC5: does NOT error when shipment_type is express and saturday_delivery is false", () => {
    const input: ShipmentRequest = {
      recipient_name: "Jane Doe",
      weight_kg: 10,
      shipment_type: "express",
      saturday_delivery: false,
    };
    const result = validateShipmentRequest(input);
    expect(result.errors).not.toContainEqual({
      field: "saturday_delivery",
